parameters.jsCode:
const response = $input.first().json;
const employees = response.result;
const domain = $('Read Domains from Sheet').first().json.domain;
const dept     = $('Set Target Filters').first().json.department;
const seniority= $('Set Target Filters').first().json.seniority;

if (!Array.isArray(employees) || employees.length === 0) {
  return [{ json: {
    domain, name: 'No results', jobTitle: '', email: '',
    linkedinUrl: '', company: '', department: dept,
    city: '', country: '', headline: '', companyLinkedinUrl: ''
  }}];
}

return employees.map(emp => ({
  json: {
    domain,
    name:               emp.name             || '',
    jobTitle:           emp.jobTitle          || emp.job_title     || '',
    email:              emp.email             || '',
    linkedinUrl:        emp.linkedinUrl       || emp.linkedin_url  || '',
    company:            emp.company           || '',
    department:         emp.department        || dept,
    city:               emp.city              || '',
    country:            emp.country           || '',
    headline:           emp.headline          || '',
    companyLinkedinUrl: emp.companyLinkedinUrl || emp.companylinkedinurl || ''
  }
}));
